// Generated by Selenium IDE
const { Builder, By, Key, until } = require('selenium-webdriver');
const assert = require('assert');
require('chromedriver');

describe('Check label JP', function() {
  this.timeout(30000);
  let driver;
  let vars;
  beforeEach(async function() {
    driver = await new Builder().forBrowser('chrome').build();
    vars = {};
  });
  afterEach(async function() {
    await driver.quit();
  });
  it('Check label JP', async function() {
    // Test name: Check label JP
    // Step # | name | target | value
    // 1 | open | http://localhost:4200/user/list-evaluation | 
    await driver.get("http://localhost:4200/user/list-evaluation");

    // 2 | setWindowSize | 1936x1056 | 
    await driver.manage().window().setRect({ width: 1936, height: 1056 });

    // 3 | click | css=.ant-layout-content | 
    await driver.findElement(By.css(".ant-layout-content")).click();

    // 4 | click | name=Search | 
    await driver.findElement(By.name("Search")).click();

    // 5 | click | css=.ant-table-cell-row-hover:nth-child(2) | 
    await driver.findElement(By.css(".ant-table-cell-row-hover:nth-child(2)")).click();

    // 6 | verifyText | css=.ant-card-body .ant-typography | 評価目標詳細
    assert(await driver.findElement(By.css(".ant-card-body .ant-typography")).getText() == "評価目標詳細");

    // 7 | verifyText | xpath=//label[contains(.,'2022年下期評価表')] | 2022年下期評価表
    assert(await driver.findElement(By.xpath("//label[contains(.,\'2022年下期評価表\')]")).getText() == "2022年下期評価表");

    // 8 | verifyText | css=.ant-form-item:nth-child(2) .ant-form-item-no-colon | 評価期間
    assert(await driver.findElement(By.css(".ant-form-item:nth-child(2) .ant-form-item-no-colon")).getText() == "評価期間");

    // 9 | verifyText | css=.ant-form-item:nth-child(3) .ant-form-item-no-colon | 氏名
    assert(await driver.findElement(By.css(".ant-form-item:nth-child(3) .ant-form-item-no-colon")).getText() == "氏名");

    // 10 | verifyText | css=.ant-form-item:nth-child(4) .ant-form-item-no-colon | 部署
    assert(await driver.findElement(By.css(".ant-form-item:nth-child(4) .ant-form-item-no-colon")).getText() == "部署");

    // 11 | verifyText | css=.ant-form-item:nth-child(5) .ant-form-item-no-colon | 等級
    assert(await driver.findElement(By.css(".ant-form-item:nth-child(5) .ant-form-item-no-colon")).getText() == "等級");

    // 12 | verifyText | css=.ant-form-item:nth-child(6) .ant-form-item-no-colon | 評価者
    assert(await driver.findElement(By.css(".ant-form-item:nth-child(6) .ant-form-item-no-colon")).getText() == "評価者");

    // 13 | verifyText | css=.ant-form-item:nth-child(7) .ant-form-item-no-colon | 状態
    assert(await driver.findElement(By.css(".ant-form-item:nth-child(7) .ant-form-item-no-colon")).getText() == "状態");

    // 14 | verifyText | css=#rc-tabs-3-tab-1 > span | 部門目標
    assert(await driver.findElement(By.css("#rc-tabs-3-tab-1 > span")).getText() == "部門目標");

    // 15 | verifyText | css=.ant-table-thead .ant-table-cell:nth-child(2) | 部門目標
    assert(await driver.findElement(By.css(".ant-table-thead .ant-table-cell:nth-child(2)")).getText() == "部門目標");

    // 16 | verifyText | css=.ant-table-thead .ant-table-cell:nth-child(3) | 指標・水準 (達成数値)
    assert(await driver.findElement(By.css(".ant-table-thead .ant-table-cell:nth-child(3)")).getText() == "指標・水準 (達成数値)");

    // 17 | verifyText | css=.ant-table-thead .ant-table-cell:nth-child(4) | 手段・方法 (どのように)
    assert(await driver.findElement(By.css(".ant-table-thead .ant-table-cell:nth-child(4)")).getText() == "手段・方法 (どのように)");

    // 18 | verifyText | css=.ant-table-thead .ant-table-cell:nth-child(5) | ウェイト
    assert(await driver.findElement(By.css(".ant-table-thead .ant-table-cell:nth-child(5)")).getText() == "ウェイト");

    // 19 | verifyText | css=.ant-table-thead .ant-table-cell:nth-child(6) | 難易度(本人)
    assert(await driver.findElement(By.css(".ant-table-thead .ant-table-cell:nth-child(6)")).getText() == "難易度(本人)");

    // 20 | verifyText | css=.ant-row > .ant-btn:nth-child(1) > span | 一時保存
    assert(await driver.findElement(By.css(".ant-row > .ant-btn:nth-child(1) > span")).getText() == "一時保存");

    // 21 | verifyText | css=.ant-col > .ant-btn:nth-child(2) > span | 評価基準
    assert(await driver.findElement(By.css(".ant-col > .ant-btn:nth-child(2) > span")).getText() == "評価基準");

    // 22 | verifyText | css=.ant-col > .ant-btn:nth-child(1) > span | 承認履歴
    assert(await driver.findElement(By.css(".ant-col > .ant-btn:nth-child(1) > span")).getText() == "承認履歴");

    // 23 | verifyText | css=.ant-row > .ant-btn:nth-child(2) > span | 提 出
    assert(await driver.findElement(By.css(".ant-row > .ant-btn:nth-child(2) > span")).getText() == "提 出");
  });
});
